import static com.ibm.integration.test.v1.Matchers.equalsMessage;
import static com.ibm.integration.test.v1.Matchers.nodeCallCountIs;
import static com.ibm.integration.test.v1.Matchers.terminalPropagateCountIs;
import static org.hamcrest.MatcherAssert.assertThat;

import java.io.InputStream;

import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;

import com.ibm.integration.test.v1.NodeSpy;
import com.ibm.integration.test.v1.SpyObjectReference;
import com.ibm.integration.test.v1.TestMessageAssembly;
import com.ibm.integration.test.v1.TestSetup;
import com.ibm.integration.test.v1.exception.TestException;

mandatory_cleanup.code:
@AfterEach
public void cleanupTest() throws TestException {
    TestSetup.restoreAllMocks();
}

helper_method_load_assembly.code:
private TestMessageAssembly loadAssembly(String resourcePath) throws TestException {
    TestMessageAssembly assembly = new TestMessageAssembly();
    try {
        InputStream stream = Thread.currentThread()
                .getContextClassLoader()
                .getResourceAsStream(resourcePath);
        if (stream == null) {
            throw new TestException("Cannot find recorded message: " + resourcePath);
        }
        assembly.buildFromRecordedMessageAssembly(stream);
    } catch (Exception ex) {
        throw new TestException("Failed to load recorded message: " + resourcePath, ex);
    }
    return assembly;
}

pattern.code:
@Test
@DisplayName("[FLOW] — [NODE] TC001 — [description] (recorded)")
public void [flow]_[Node]_TC001() throws TestException {

    // Spy on the node under test
    SpyObjectReference nodeRef = new SpyObjectReference()
            .application("[APP]")
            .messageFlow("[FLOW]")
            .node("[NODE]");

    NodeSpy nodeSpy = new NodeSpy(nodeRef);

    // Inject the recorded input checkpoint
    TestMessageAssembly inputAssembly = loadAssembly("/[INPUT].mxml");

    // Execute the node
    nodeSpy.evaluate(inputAssembly, true, "in");

    // Assert the node was called once
    assertThat(nodeSpy, nodeCallCountIs(1));

    // Assert it propagated via the expected terminal
    assertThat(nodeSpy, terminalPropagateCountIs("[TERMINAL]", 1));

    // Get the actual output and compare to the recorded expected output
    TestMessageAssembly actualOutput   = nodeSpy.propagatedMessageAssembly("[TERMINAL]", 1);
    TestMessageAssembly expectedOutput = loadAssembly("/[EXPECTED].mxml");

    assertThat(actualOutput, equalsMessage(expectedOutput));
}

nodeSpy.evaluate(inputAssembly, true, "in");
assertThat(nodeSpy, nodeCallCountIs(1));
assertThat(nodeSpy, terminalPropagateCountIs("out", 1));
// No equalsMessage — just verifying routing behaviour

// Spy on the node that should NOT fire (e.g. HTTP Request)
SpyObjectReference httpRequestRef = new SpyObjectReference()
        .application("[APP]")
        .messageFlow("[FLOW]")
        .node("HTTP Request");

NodeSpy httpRequestSpy = new NodeSpy(httpRequestRef);

// Stop BEFORE the HTTP Request node sends its message out
httpRequestSpy.setStopAtInputTerminal("in");

// Now spy on and drive the upstream node
SpyObjectReference computeRef = new SpyObjectReference()
        .application("[APP]")
        .messageFlow("[FLOW]")
        .node("Prepare Request");

NodeSpy computeSpy = new NodeSpy(computeRef);
computeSpy.propagate(loadAssembly("/[INPUT].mxml"), "out");

// Assert the HTTP Request node received the correct message
assertThat(httpRequestSpy, nodeCallCountIs(1));

step.fallback_when_ibmint_unavailable:
If ibmint is not available (ACE version below 12.0.8, or profile not sourced),
use this PowerShell snippet to extract source and target from each .mxml:

  Get-ChildItem *.mxml | Sort-Object Name | ForEach-Object {
    $raw = Get-Content $_.FullName -Raw
    $src = if ($raw -match '<source>.*?<name[^>]*>([^<]+)<')  { $Matches[1] } else { '?' }
    $tgt = if ($raw -match '<target>.*?<name[^>]*>([^<]+)<')  { $Matches[1] } else { '?' }
    $prop = if ($raw -match '<propagationCount[^>]*>(\d+)<') { $Matches[1] } else { '?' }
    Write-Host "$($_.Name)  prop=$prop  $src -> $tgt"
  }

Or use the xmllint bash script documented in Section 14 on Linux/AIX.

enhancements.enhancement:
Add terminalPropagateCountIs() assertions alongside equalsMessage() to confirm
the correct terminal was used — not just the message content.
Example: assertThat(nodeSpy, terminalPropagateCountIs("failure", 1));

complete_example.java_class:
package com.weather.api.test;

import static com.ibm.integration.test.v1.Matchers.equalsMessage;
import static com.ibm.integration.test.v1.Matchers.nodeCallCountIs;
import static com.ibm.integration.test.v1.Matchers.terminalPropagateCountIs;
import static org.hamcrest.MatcherAssert.assertThat;
import java.io.InputStream;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;
import com.ibm.integration.test.v1.NodeSpy;
import com.ibm.integration.test.v1.SpyObjectReference;
import com.ibm.integration.test.v1.TestMessageAssembly;
import com.ibm.integration.test.v1.TestSetup;
import com.ibm.integration.test.v1.exception.TestException;

public class WeatherAPITest {

    private static final String APP  = "WeatherAPI_App";
    private static final String FLOW = "getCurrentWeather";

    @AfterEach
    public void cleanupTest() throws TestException {
        TestSetup.restoreAllMocks();
    }

    private TestMessageAssembly loadAssembly(String path) throws TestException {
        TestMessageAssembly a = new TestMessageAssembly();
        try {
            InputStream s = Thread.currentThread().getContextClassLoader().getResourceAsStream(path);
            if (s == null) throw new TestException("Cannot find: " + path);
            a.buildFromRecordedMessageAssembly(s);
        } catch (Exception ex) { throw new TestException("Failed to load: " + path, ex); }
        return a;
    }

    @Test
    @DisplayName("getCurrentWeather — Prepare Request TC001 — location=London builds backend URL (recorded)")
    public void getCurrentWeather_PrepareRequest_TC001() throws TestException {
        NodeSpy nodeSpy = new NodeSpy(new SpyObjectReference().application(APP).messageFlow(FLOW).node("Prepare Request"));
        nodeSpy.evaluate(loadAssembly("/000071A0-6A4EAD36-00000001-0.mxml"), true, "in");
        assertThat(nodeSpy, nodeCallCountIs(1));
        assertThat(nodeSpy, terminalPropagateCountIs("out", 1));
        assertThat(nodeSpy.propagatedMessageAssembly("out", 1),
                equalsMessage(loadAssembly("/000071A0-6A4EAD36-00000001-1.mxml")));
    }

    @Test
    @DisplayName("getCurrentWeather — HTTP Request TC001 — calls backend, returns London weather (recorded)")
    public void getCurrentWeather_HTTPRequest_TC001() throws TestException {
        NodeSpy nodeSpy = new NodeSpy(new SpyObjectReference().application(APP).messageFlow(FLOW).node("HTTP Request"));
        nodeSpy.evaluate(loadAssembly("/000071A0-6A4EAD36-00000001-1.mxml"), true, "in");
        assertThat(nodeSpy, nodeCallCountIs(1));
        assertThat(nodeSpy, terminalPropagateCountIs("out", 1));
        assertThat(nodeSpy.propagatedMessageAssembly("out", 1),
                equalsMessage(loadAssembly("/000071A0-6A4EAD36-00000001-2.mxml"))
                    .ignorePath("/Message/BLOB/BLOB", false)
                    .ignorePath("/Message/HTTPResponseHeader/Date", false)
                    .ignorePath("/Message/HTTPResponseHeader/CDN-CachedAt", false)
                    .ignorePath("/Message/HTTPResponseHeader/CDN-RequestId", false)
                    .ignorePath("/Message/HTTPResponseHeader/CDN-Cache", false)
                    .ignorePath("/Message/HTTPResponseHeader/x-weatherapi-qpm-left", false)
                    .ignorePath("/LocalEnvironment/WrittenDestination", true));
    }
}

nodestub_api.required_imports:
import com.ibm.integration.test.v1.NodeStub;
import com.ibm.integration.test.v1.NodeSpy;
import com.ibm.integration.test.v1.SpyObjectReference;
import com.ibm.integration.test.v1.TestMessageAssembly;
import com.ibm.integration.test.v1.TestSetup;
import com.ibm.integration.test.v1.exception.TestException;

pattern.code:
@Test
@DisplayName("WholeFlow — Normal path — input arrives at expected output nodes")
public void wholeFlow_FlowOrder_Test() throws TestException {

    // 1. Spy on the INPUT node to inject the recorded message
    SpyObjectReference inputNodeRef = new SpyObjectReference()
            .application("Common_Realtime_Workflow")
            .messageFlow("Common_Realtime_Workflow_MF")
            .node("IIBHUB.COMMONREALTIME.INPUT");   // label of the MQ Input node

    NodeSpy inputNodeSpy = new NodeSpy(inputNodeRef);

    // 2. Stub OUTPUT nodes to prevent real MQ writes
    SpyObjectReference salesforceOutputRef = new SpyObjectReference()
            .application("Common_Realtime_Workflow")
            .messageFlow("Common_Realtime_Workflow_MF")
            .node("IIBHUB.SALESFORCE.INPUT");       // label of the MQ Output node

    NodeStub salesforceStub = new NodeStub(salesforceOutputRef);
    salesforceStub.setStopAtInputTerminal("in");    // intercept before the node fires

    SpyObjectReference dbReportingOutputRef = new SpyObjectReference()
            .application("Common_Realtime_Workflow")
            .messageFlow("Common_Realtime_Workflow_MF")
            .node("IIBHUB.DBREPORTING.INPUT");

    NodeStub dbReportingStub = new NodeStub(dbReportingOutputRef);
    dbReportingStub.setStopAtInputTerminal("in");

    // 3. Stub the HTTP Request node inside the subflow to mock the external service
    SpyObjectReference httpRequestRef = new SpyObjectReference()
            .application("Common_Realtime_Workflow")
            .messageFlow("Common_Realtime_Workflow_MF")
            .subflowNode("CommonMemberPreference")  // subflow instance label
            .node("MemInqHTTP Request");             // node inside the subflow

    NodeStub httpRequestStub = new NodeStub(httpRequestRef);
    // Provide a recorded response to feed back into the flow
    TestMessageAssembly mockResponse = loadAssembly("/recorded_http_response.mxml");
    httpRequestStub.setReturnValue(mockResponse, "out");   // replay recorded response

    // 4. Inject the input message
    TestMessageAssembly inputMsg = loadAssembly("/IIBHUB.COMMONREALTIME.INPUT-0.mxml");
    inputNodeSpy.evaluate(inputMsg, true, "out");          // drive from input node

    // 5. Assert messages arrived at expected output stubs
    assertThat(salesforceStub, nodeCallCountIs(1));
    assertThat(dbReportingStub, nodeCallCountIs(1));

    // 6. Optionally compare content against recorded expected assemblies
    assertThat(salesforceStub.propagatedMessageAssembly("in", 1),
            equalsMessage(loadAssembly("/IIBHUB.SALESFORCE.INPUT-expected.mxml")));
}

@Test
@DisplayName("WholeFlow — Error path — catch terminal routes to error output")
public void wholeFlow_LogError_Test() throws TestException {

    // Stub the error output node
    SpyObjectReference errorReplayRef = new SpyObjectReference()
            .application("Common_Realtime_Workflow")
            .messageFlow("Common_Realtime_Workflow_MF")
            .node("COMMON.ERRORREPLAY");

    NodeStub errorReplayStub = new NodeStub(errorReplayRef);
    errorReplayStub.setStopAtInputTerminal("in");

    // Spy on the input node
    SpyObjectReference inputRef = new SpyObjectReference()
            .application("Common_Realtime_Workflow")
            .messageFlow("Common_Realtime_Workflow_MF")
            .node("IIBHUB.COMMONREALTIME.INPUT");

    NodeSpy inputSpy = new NodeSpy(inputRef);

    // Inject a recorded message that triggers the error scenario
    TestMessageAssembly errorInput = loadAssembly("/error-scenario-input.mxml");
    inputSpy.evaluate(errorInput, true, "out");

    // Verify the error output was triggered
    assertThat(errorReplayStub, nodeCallCountIs(1));
}

step.shell_script:
#!/bin/bash # run_all_generated_tests.sh # Usage: ./run_all_generated_tests.sh <BrokerName> <ExecutionGroupName> <QueueManagerName> [--log-mode file|console]
BROKER_NAME=$1 EG_NAME=$2 QM_NAME=$3 LOG_MODE=${4:-console}
WORK_DIR="/var/mqsi/components/${BROKER_NAME}/servers/${EG_NAME}"
for test_project in "${WORK_DIR}/run"/GenTest_*; do project_name=$(basename "$test_project") echo "Running test project: $project_name" IntegrationServer \ --work-dir "$WORK_DIR" \ --no-nodejs \ --start-msgflows false \ --mq-queue-manager-name "$QM_NAME" \ --test-project "$project_name" done

